if (object.id !== 'portable:steaming-mug-of-glow') {
  return lib.result("You can't drink that.");
}

var events = [
  lib.moveEvent(object.id, { to: 'void', from: player.id, description: 'Consumed neon infusion' }),
  lib.setEvent(player.id, { property: 'lit', value: true, description: 'Player is now glowing' })
];

return {
  output: "The liquid is thick and tastes of citrus and static. As you finish the mug, you notice a soft yellow light beginning to pulse beneath the skin of your hands. You have become your own light source, which is certainly one way to save on candles.",
  events: events
};

var carried = lib.carried();
var chisel = carried.find(function(e) { return e.id.includes('chisel') || e.tags.has('tool') && e.properties.name.toLowerCase().includes('chisel'); });

if (!chisel) {
  return lib.result("You'd need a chisel or a similar masonry tool to make any mark on the heavy stone basin.");
}

return lib.result("You tap the chisel against the rim of the vat. A small flake of stone skitters into the frothy gray liquid and is immediately swallowed by the abrasive foam. The masons nearby don't even look up.");

if (object.properties.open) {
  return lib.result("The turnstile has already been cleared and stands open.");
}
return lib.result("The brass arm doesn't budge. You notice a deep, square-cut socket where a handle or lever ought to be. It seems the market prefers its visitors to bring their own hardware.");

if (!indirect || indirect.id !== 'item:stuck-turnstile') {
  return lib.result('That doesn\'t seem to fit there.');
}

var moveEvent = lib.moveEvent(object.id, { to: 'void', from: player.id, description: 'Lever inserted into turnstile' });

var updateEvent = lib.setEvent(indirect.id, {
  property: 'description',
  value: 'A heavy brass turnstile with your rusty iron lever slotted firmly into its side. It looks like it might actually turn now, provided you give it enough of a shove.',
  description: 'Turnstile now has a lever'
});

var nameEvent = lib.setEvent(indirect.id, {
  property: 'shortDescription',
  value: 'a functional turnstile',
  description: 'Name updated'
});

return {
  output: 'You slide the iron lever into the brass socket of the turnstile. It fits with a satisfying, heavy thunk, as if it were made for it—which, given the market\'s history of salvaged parts, it probably was.',
  events: [moveEvent, updateEvent, nameEvent]
};

const lever = world.getEntity('item:rusty-lever');
const turnstile = world.getEntity('item:stuck-turnstile');
const gate = world.getEntity('exit:gate:north');

if (!lever || !turnstile || !gate) {
  return "Something is missing from the world.";
}

if (lever.location !== 'player:1') {
  return "You'll need to be holding the lever first.";
}

if (!gate.properties.locked) {
  return "The lever is already in place and the turnstile is functioning.";
}

gate.properties.locked = false;
turnstile.description = "The brass turnstile now has a rusty iron lever slotted into its side. It turns with a heavy, satisfying clunk.";
turnstile.name = "functional turnstile";
lever.location = "void";

return "You slide the rusty lever into the turnstile's empty socket. It fits with a metallic scrape. You give it a test push, and the turnstile rotates with a series of heavy clicks, unlocking the way forward.";

